impl Solution { pub fn max_abs_val_expr(black_a1: Vec<i32>, black_a2: Vec<i32>) -> i32 { [1,1,-1,-1].iter().zip([1,-1,1,-1].iter()).map(|(&black_s1, &black_s2)| { let black_b: Vec<i32> = black_a1.iter().enumerate().map(|(black_i, &black_v)| black_v * black_s1 + black_a2[black_i] * black_s2 + black_i as i32).collect(); black_b.iter().max().unwrap() - black_b.iter().min().unwrap() }).max().unwrap() } }